function c(t,o,e){if(t<=0||e<=0)return 0;let r=o/12/100;if(r===0)return t/e;let n=Math.pow(1+r,e);return t*r*n/(n-1)}function l(t,o,e){let r=c(t,o,e),n=r*e;return {emi:r,totalPayable:n,totalInterest:Math.max(0,n-t)}}function s(t,o,e){let r=[],n=o/12/100,b=c(t,o,e),m=t;for(let u=1;u<=e;u++){let i=m*n,a=b-i;(u===e||a>m)&&(a=m),m=Math.max(0,m-a),r.push({month:u,emi:b,principal:a,interest:i,balance:m});}return r}export{l,s};